module full_adder_4bit(
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout
);

wire [3:0] overflow;

assign {overflow[0], sum[0]} = a[0] + b[0] + cin;
assign {overflow[1], sum[1]} = a[1] + b[1] + overflow[0];
assign {overflow[2], sum[2]} = a[2] + b[2] + overflow[1];
assign {overflow[3], sum[3]} = a[3] + b[3] + overflow[2];
assign cout = overflow[3];

endmodule
